INSERT INTO resenha_diaria (tipo_ato, numero_ato, ementa, url, data_publicacao, data_dou)
VALUES
-- 8 de abril de 2026 - Edição extra
('Decreto', 'Decreto nº 12.924, de 8.4.2026', 'Altera o Decreto nº 5.059, de 30 de abril de 2004, para reduzir as alíquotas da Contribuição para o Programa de Integração Social e para o Programa de Formação do Patrimônio do Servidor Público – PIS/Pasep e da Contribuição para o Financiamento da Seguridade Social – Cofins incidentes sobre a importação e a comercialização de querosene de aviação.', 'http://www.planalto.gov.br/ccivil_03/_ato2023-2026/2026/Decreto/D12924.htm', '8 de abril de 2026 - Edição extra', '2026-04-08'),
-- 7 de abril de 2026 - Edição extra
('Medida Provisória', 'Medida Provisória nº 1.349, de 7.4.2026', 'Institui o Regime Emergencial de Abastecimento Interno de Combustíveis e altera a Medida Provisória nº 1.340, de 12 de março de 2026, a Lei nº 9.847, de 26 de outubro de 1999, e a Lei nº 12.462, de 4 de agosto de 2011.', 'http://www.planalto.gov.br/ccivil_03/_ato2023-2026/2026/Mpv/mpv1349.htm', '7 de abril de 2026 - Edição extra', '2026-04-07'),
('Decreto', 'Decreto nº 12.923, de 7.4.2026', 'Altera o Decreto nº 10.527, de 22 de outubro de 2020, para reduzir as alíquotas da Contribuição para o Programa de Integração Social e o Programa de Formação do Patrimônio do Servidor Público – PIS/Pasep e da Contribuição para o Financiamento da Seguridade Social – Cofins incidentes sobre a importação e a comercialização de biodiesel.', 'http://www.planalto.gov.br/ccivil_03/_ato2023-2026/2026/Decreto/D12923.htm', '7 de abril de 2026 - Edição extra', '2026-04-07'),
('Decreto', 'Decreto nº 12.922, de 7.4.2026', 'Altera o Decreto nº 7.212, de 15 de junho de 2010, para inibir a expansão do tabagismo no País, e o Decreto nº 12.226, de 18 de outubro de 2024, para dispor sobre critérios para qualificação de país ou dependência com tributação favorecida ou de regime fiscal privilegiado.', 'http://www.planalto.gov.br/ccivil_03/_ato2023-2026/2026/Decreto/D12922.htm', '7 de abril de 2026 - Edição extra', '2026-04-07'),
-- 7 de abril de 2026
('Lei', 'Lei nº 15.380, de 6.4.2026', 'Altera a Lei nº 11.340, de 7 de agosto de 2006 (Lei Maria da Penha), para estabelecer que a audiência de retratação nos casos de violência doméstica e familiar contra a mulher somente seja realizada mediante manifestação expressa da vítima, apresentada antes do recebimento da denúncia.', 'http://www.planalto.gov.br/ccivil_03/_ato2023-2026/2026/Lei/L15380.htm', '7 de abril de 2026', '2026-04-07'),
('Lei', 'Lei nº 15.379, de 6.4.2026', 'Altera a Lei nº 8.080, de 19 de setembro de 1990 (Lei Orgânica da Saúde), para incluir a imunoterapia nos protocolos clínicos e nas diretrizes terapêuticas do câncer.', 'http://www.planalto.gov.br/ccivil_03/_ato2023-2026/2026/Lei/L15379.htm', '7 de abril de 2026', '2026-04-07'),
('Lei', 'Lei nº 15.378, de 6.4.2026', 'Institui o Estatuto dos Direitos do Paciente.', 'http://www.planalto.gov.br/ccivil_03/_ato2023-2026/2026/Lei/L15378.htm', '7 de abril de 2026', '2026-04-07'),
('Decreto', 'Decreto nº 12.921, de 6.4.2026', 'Regulamenta a Lei nº 14.725, de 16 de novembro de 2023, que regula a profissão de sanitarista.', 'http://www.planalto.gov.br/ccivil_03/_ato2023-2026/2026/Decreto/D12921.htm', '7 de abril de 2026', '2026-04-07'),
-- 6 de abril de 2026 - Edição extra (faltantes)
('Medida Provisória', 'Medida Provisória nº 1.348, de 6.4.2026', 'Altera a Lei Complementar nº 89, de 18 de fevereiro de 1997, para dispor sobre as receitas e a destinação de recursos do Fundo para Aparelhamento e Operacionalização das Atividades-fim da Polícia Federal – FUNAPOL e sobre o auxílio-saúde dos servidores das polícias federais, e a Lei nº 13.756, de 12 de dezembro de 2018, para ajustar a destinação do produto da arrecadação das apostas de quota fixa.', 'http://www.planalto.gov.br/ccivil_03/_ato2023-2026/2026/Mpv/mpv1348.htm', '6 de abril de 2026 - Edição extra', '2026-04-06'),
('Decreto', 'Decreto nº 12.920, de 6.4.2026', 'Altera o Decreto nº 3.184, de 27 de setembro de 1999, que dispõe sobre a concessão de indenização de transporte aos servidores públicos da Administração direta, autárquica e fundacional do Poder Executivo da União.', 'http://www.planalto.gov.br/ccivil_03/_ato2023-2026/2026/Decreto/D12920.htm', '6 de abril de 2026 - Edição extra', '2026-04-06')
